import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, MyTable, HighlightedInfo } from '../../../includes';
import { routeNamesInventory } from '../../routeNames';
import { stockActions } from '../actions';
import { stockStrings } from '../config';
import StockTakingHeaderComponent from './StockTakingHeaderComponent';
import { TableCell } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 30
    }
})
class _StockTaking extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : StockTaking.rows
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "STOCK TAKING",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Stock Taking", path : routeNamesInventory.stockTaking},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                StockTakingHeaderComponent
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    static rows = 20
    initialiseComponent(){
        const{
            dispatch,
            [stockStrings.stockCategories] : stockCategories,
            [stockStrings.itemForms]  : itemForms,
            [stockStrings.itemPackages] : itemPackages,
        } = this.props;
        stockActions.getStores()(dispatch);
        if(!stockCategories) stockActions.getStockCategories()(dispatch);
        if(!itemForms) stockActions.getItemFroms()(dispatch);
        if(!itemPackages) stockActions.getItemPackages()(dispatch);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {
            classes,
            [stockStrings.stockCategories] : stockCategories,
            [stockStrings.itemForms] : itemForms,
            [stockStrings.itemPackages] : itemPackages,
        } = this.props;
        let a = {
            storeId : 1, 
            stock : [ 
                {packageId : 1, count : 3},
                {packageId : 2, count : 1},
            ]
        };
        switch(cellMap){
            case "stock" : 
            if(row.stockInfo && row.stockInfo.stock){
                const stock = row.stockInfo.stock;
                return <TableCell className={classes.cell}>
                    {stock && stock.map((item, index)=>{
                        const {packageId, count} = item;
                        const {item : packageItem} = itemPackages.getFirstObjectByPropValue("_id", packageId);
                        if(packageItem){
                            return <div key={index}><strong>{packageItem.name}: </strong>{Number(count).toLocaleString()}</div>
                        }else return null;
                    })}
                </TableCell>
            } return <TableCell></TableCell>;
            case "categoryId" : 
                if(!stockCategories) return <TableCell className={classes.cell}/>;
                let category = null;
                if(stockCategories){
                    const {item : catItem} = stockCategories.getFirstObjectByPropValue("_id", row.item.categoryId);
                    if(catItem) category = catItem.name;
                }
                return <TableCell className={classes.cell}>
                    {category}
                </TableCell>
            case "formId" : 
                if(!itemForms) return <TableCell className={classes.cell}/>;
                let form = null;
                if(itemForms){
                    const {item : formItem} = itemForms.getFirstObjectByPropValue("_id", row.item.formId);
                    if(formItem) form = formItem.name;
                }
                return <TableCell className={classes.cell}>
                    {form}
                </TableCell>
            case "brand" : return <TableCell className={classes.cell}>
                {row.item.brand}
            </TableCell>
            case "itemId" : return <TableCell className={classes.cell}>
                {row.item.name}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {
            classes,
            [stockStrings.storeStocks] : storeStocks,
            [stockStrings.selectedStore] : selectedStore,
        } = this.props;
        
        return (
            <div className={classes.root}>
                {selectedStore ? <MyTable
                    header={["ID", "Item", "Form", "Brand", "Category", "Stock"]}
                    dataMap={["_id", "itemId", "formId", "brand", "categoryId", "stock"]}
                    data={storeStocks}
                    CellMap={this.cellMapFormat.bind(this)}/> :

                <HighlightedInfo>
                    Select a store to view its stock!
                </HighlightedInfo>}
            </div>
        );
    }
}


_StockTaking.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.selectedStore] : stockReducer[stockStrings.selectedStore],
    [stockStrings.storeStocks] : stockReducer[stockStrings.storeStocks],
    [stockStrings.stockCategories] : stockReducer[stockStrings.stockCategories],
    [stockStrings.itemForms]  : stockReducer[stockStrings.itemForms] ,
    [stockStrings.itemPackages] : stockReducer[stockStrings.itemPackages],
})


export const StockTaking = connect(mapStateToProps)(withStyles(style)(_StockTaking));
export {StockTaking as default}